import React from 'react';
import Header from '../../componets/header/Header';
import Footer from '../../componets/footer/Footer';
import BlogSEO from '../../componets/BlogSEO/BlogSEO';
import { getAllPosts, getPostBySlug } from '../../data/blogData';
import { getBlogContent } from '../../content/content_blog';
import { useLanguage } from '../../context/LanguageContext';
import './blog-post.css';

interface BlogPostTemplateProps {
    pageContext: {
        slug: string;
        post?: {
            id: string;
            title: string;
            description: string;
            author: {
                name: string;
                avatar?: string;
            };
            date: string;
            image: string;
            category: string;
            slug: string;
        };
    };
}

const BlogPostTemplate: React.FC<BlogPostTemplateProps> = ({ pageContext }) => {
    const { slug } = pageContext;
    const { lang } = useLanguage();
    const blogPosts = getAllPosts(lang);
    const content = getBlogContent(lang).blogPostContent;

    // Fetch the full post data based on slug and current language
    const post = getPostBySlug(slug, lang);

    // If post not found, show error
    if (!post) {
        return (
            <main className="blog-post-page">
                <Header />
                <div style={{ padding: '4rem 2rem', textAlign: 'center', color: 'white' }}>
                    <h1>Post not found</h1>
                    <a href="/blog">Back to Blog</a>
                </div>
                <Footer />
            </main>
        );
    }

    // Find related posts (same category, exclude current)
    const relatedPosts = blogPosts
        .filter(p => p.category === post.category && p.slug !== post.slug)
        .slice(0, 3);

    return (
        <main className="blog-post-page">
            <BlogSEO post={post} lang={lang} />
            <Header />

            {/* Blog Post Hero */}
            <section className="blog-post-hero">
                <div className="blog-post-hero__overlay"></div>
                <div className="blog-post-hero__inner">
                    <div className="blog-post-hero__meta">
                        <span className="blog-post-hero__category">{post.category}</span>
                        <span className="blog-post-hero__date">{post.date}</span>
                    </div>
                    <h1 className="blog-post-hero__title">{post.title}</h1>
                    <div className="blog-post-hero__author">
                        {post.author.avatar && (
                            <span className="blog-post-hero__avatar">{post.author.avatar}</span>
                        )}
                        <span className="blog-post-hero__author-name">{content.by} {post.author.name}</span>
                    </div>
                </div>
            </section>

            {/* Featured Image */}
            <section className="blog-post-image">
                <div className="blog-post-image__inner">
                    <div className="blog-post-image__wrapper">
                        <img
                            src={post.image}
                            alt={post.title}
                            className="blog-post-image__img"
                            onError={(e) => {
                                e.currentTarget.style.display = 'none';
                            }}
                        />
                        <div className="blog-post-image__overlay"></div>
                    </div>
                </div>
            </section>

            {/* Blog Post Content */}
            <article className="blog-post-content">
                <div className="blog-post-content__inner">
                    <div className="blog-post-content__body">
                        {/* Introduction */}
                        <p className="blog-post-intro">{post.description}</p>

                        {/* Main Content - Placeholder sections */}
                        <h2>{lang === "en" ? `Understanding ${post.title.split(' ').slice(0, 3).join(' ')}` : `Hiểu về ${post.title.split(' ').slice(0, 3).join(' ')}`}</h2>
                        <p>
                            {lang === "en"
                                ? "At Tinh Hoa Việt, we believe in celebrating excellence and preserving the rich cultural heritage of the Vietnamese community. This article explores the deeper meaning behind our mission and how it connects with traditional Vietnamese values."
                                : "Tại Tinh Hoa Việt, chúng tôi tin tưởng vào việc tôn vinh sự xuất sắc và bảo tồn di sản văn hóa phong phú của cộng đồng Việt Nam. Bài viết này khám phá ý nghĩa sâu sắc đằng sau sứ mệnh của chúng tôi và cách nó kết nối với các giá trị truyền thống Việt Nam."}
                        </p>

                        <p>
                            {lang === "en"
                                ? "Our community continues to demonstrate remarkable resilience and achievement across various fields. From business leadership to academic excellence, from cultural preservation to technological innovation, Vietnamese individuals worldwide are making significant contributions to their communities."
                                : "Cộng đồng của chúng tôi tiếp tục thể hiện sự kiên cường và thành tựu đáng kể trên nhiều lĩnh vực. Từ lãnh đạo doanh nghiệp đến xuất sắc học thuật, từ bảo tồn văn hóa đến đổi mới công nghệ, người Việt Nam trên toàn thế giới đang đóng góp quan trọng cho cộng đồng của họ."}
                        </p>

                        <h2>{lang === "en" ? "The Five Pillars Framework" : "Khung Năm Trụ Cột"}</h2>
                        <p>
                            {lang === "en"
                                ? "The foundation of our recognition framework is built upon five essential principles: Tâm (Heart/Character), Tài (Talent/Skill), Tín (Trust/Credibility), Trí (Wisdom/Intelligence), and Thể (Physical Health). These pillars reflect the holistic view of excellence in Vietnamese culture."
                                : "Nền tảng của khung công nhận của chúng tôi được xây dựng dựa trên năm nguyên tắc thiết yếu: Tâm (Trái tim/Tính cách), Tài (Tài năng/Kỹ năng), Tín (Lòng Tin/Uy tín), Trí (Trí tuệ), và Thể (Sức khỏe). Những trụ cột này phản ánh cái nhìn toàn diện về sự xuất sắc trong văn hóa Việt Nam."}
                        </p>

                        <blockquote className="blog-post-quote">
                            {lang === "en"
                                ? "Excellence is not just about achievement, but about embodying the values that connect us to our heritage while building our future."
                                : "Sự xuất sắc không chỉ là về thành tựu, mà là về việc thể hiện các giá trị kết nối chúng ta với di sản trong khi xây dựng tương lai của chúng ta."}
                        </blockquote>

                        <h2>{lang === "en" ? "Community Impact" : "Tác Động Cộng Đồng"}</h2>
                        <p>
                            {lang === "en"
                                ? "Through our programs and events, we have witnessed the transformative power of recognition and community support. By highlighting exceptional individuals, we inspire the next generation to pursue their own paths to excellence while staying connected to their Vietnamese roots."
                                : "Thông qua các chương trình và sự kiện của chúng tôi, chúng tôi đã chứng kiến sức mạnh biến đổi của sự công nhận và hỗ trợ cộng đồng. Bằng cách nổi bật những cá nhân xuất sắc, chúng tôi truyền cảm hứng cho thế hệ tiếp theo theo đuổi con đường xuất sắc của riêng họ trong khi vẫn gắn kết với nguồn gốc Việt Nam."}
                        </p>

                        <p>
                            {lang === "en"
                                ? "We invite you to join us in this journey of celebration and inspiration. Whether through nominating outstanding community members, attending our events, or supporting our initiatives, your participation helps strengthen the bonds that unite our community."
                                : "Chúng tôi mời bạn tham gia cùng chúng tôi trong hành trình tôn vinh và truyền cảm hứng này. Dù thông qua việc đề cử các thành viên cộng đồng xuất sắc, tham dự các sự kiện của chúng tôi, hoặc hỗ trợ các sáng kiến của chúng tôi, sự tham gia của bạn giúp củng cố những liên kết kết nối cộng đồng của chúng ta."}
                        </p>

                        {/* Call to Action */}
                        <div className="blog-post-cta">
                            <h3>{lang === "en" ? "Get Involved" : "Tham Gia"}</h3>
                            <p>
                                {lang === "en"
                                    ? "Help us recognize excellence in the Vietnamese community. Nominate someone deserving of recognition or learn more about our upcoming events."
                                    : "Giúp chúng tôi công nhận sự xuất sắc trong cộng đồng Việt Nam. Đề cử người xứng đáng được công nhận hoặc tìm hiểu thêm về các sự kiện sắp tới của chúng tôi."}
                            </p>
                            <div className="blog-post-cta-buttons">
                                <a href="/nominate" className="blog-post-btn blog-post-btn--gold">
                                    {lang === "en" ? "Nominate Now" : "Đề Cử Ngay"}
                                </a>
                                <a href="/about" className="blog-post-btn blog-post-btn--ghost">
                                    {lang === "en" ? "Learn More" : "Tìm Hiểu Thêm"}
                                </a>
                            </div>
                        </div>
                    </div>

                    {/* Sidebar */}
                    <aside className="blog-post-sidebar">
                        <div className="blog-post-share">
                            <h4>{content.shareArticle}</h4>
                            <div className="blog-post-share-buttons">
                                <button className="share-btn" title="Share on Facebook">
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                                        <path d="M18 2h-3a5 5 0 00-5 5v3H7v4h3v8h4v-8h3l1-4h-4V7a1 1 0 011-1h3z" />
                                    </svg>
                                </button>
                                <button className="share-btn" title="Share on Twitter">
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                                        <path d="M23 3a10.9 10.9 0 01-3.14 1.53 4.48 4.48 0 00-7.86 3v1A10.66 10.66 0 013 4s-4 9 5 13a11.64 11.64 0 01-7 2c9 5 20 0 20-11.5a4.5 4.5 0 00-.08-.83A7.72 7.72 0 0023 3z" />
                                    </svg>
                                </button>
                                <button className="share-btn" title="Share on LinkedIn">
                                    <svg width="20" height="20" viewBox="0 0 24 24" fill="currentColor">
                                        <path d="M16 8a6 6 0 016 6v7h-4v-7a2 2 0 00-2-2 2 2 0 00-2 2v7h-4v-7a6 6 0 016-6zM2 9h4v12H2z" />
                                        <circle cx="4" cy="4" r="2" />
                                    </svg>
                                </button>
                            </div>
                        </div>

                        {relatedPosts.length > 0 && (
                            <div className="blog-post-related">
                                <h4>{content.relatedArticles}</h4>
                                <div className="related-posts">
                                    {relatedPosts.map(relatedPost => (
                                        <a
                                            key={relatedPost.id}
                                            href={`/blog/${relatedPost.slug}`}
                                            className="related-post"
                                        >
                                            <span className="related-post__category">{relatedPost.category}</span>
                                            <h5 className="related-post__title">{relatedPost.title}</h5>
                                            <span className="related-post__date">{relatedPost.date}</span>
                                        </a>
                                    ))}
                                </div>
                            </div>
                        )}
                    </aside>
                </div>
            </article>

            {/* Back to Blog */}
            <section className="blog-post-nav">
                <div className="blog-post-nav__inner">
                    <a href="/blog" className="blog-post-nav__link">
                        <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
                            <path
                                d="M13 16L7 10L13 4"
                                stroke="currentColor"
                                strokeWidth="2"
                                strokeLinecap="round"
                                strokeLinejoin="round"
                            />
                        </svg>
                        <span>{content.backToAllArticles}</span>
                    </a>
                </div>
            </section>

            <Footer />
        </main>
    );
};

export default BlogPostTemplate;
