import React from 'react';
import { Helmet } from 'react-helmet';
import { BlogPost } from '../../data/blogData';

interface BlogSEOProps {
    post: BlogPost;
    lang: 'en' | 'vn';
}

const BlogSEO: React.FC<BlogSEOProps> = ({ post, lang }) => {
    const siteUrl = typeof window !== 'undefined' ? window.location.origin : 'https://tinhhoaviet.org';
    const postUrl = `${siteUrl}/blog/${post.slug}`;
    const siteName = 'Tinh Hoa Việt';

    return (
        <Helmet>
            <title>{post.seo?.metaTitle || post.title}</title>
            <meta name="title" content={post.seo?.metaTitle || post.title} />
            <meta name="description" content={post.seo?.metaDescription || post.description} />
            {post.seo?.keywords && (
                <meta name="keywords" content={post.seo.keywords.join(', ')} />
            )}
            <meta name="author" content={post.author.name} />
            <link rel="canonical" href={postUrl} />

            <meta property="og:type" content={post.seo?.ogType || 'article'} />
            <meta property="og:url" content={postUrl} />
            <meta property="og:title" content={post.seo?.metaTitle || post.title} />
            <meta property="og:description" content={post.seo?.metaDescription || post.description} />
            <meta property="og:image" content={post.seo?.ogImage || post.image} />
            <meta property="og:site_name" content={siteName} />
            <meta property="og:locale" content={lang === 'en' ? 'en_US' : 'vi_VN'} />

            <meta property="article:published_time" content={post.date} />
            <meta property="article:author" content={post.author.name} />
            <meta property="article:section" content={post.category} />
            {post.seo?.keywords && post.seo.keywords.map((keyword: string) => (
                <meta key={keyword} property="article:tag" content={keyword} />
            ))}

            <meta property="twitter:card" content="summary_large_image" />
            <meta property="twitter:url" content={postUrl} />
            <meta property="twitter:title" content={post.seo?.metaTitle || post.title} />
            <meta property="twitter:description" content={post.seo?.metaDescription || post.description} />
            <meta property="twitter:image" content={post.seo?.ogImage || post.image} />

            <meta name="language" content={lang === 'en' ? 'English' : 'Vietnamese'} />
            <meta name="robots" content="index, follow" />
            <meta name="googlebot" content="index, follow" />
        </Helmet>
    );
};

export default BlogSEO;
